import loggingfrom sqlalchemy import selectfrom sqlalchemy.orm import Sessionfrom BookStore.app.core.config import settingsfrom BookStore.app.models.model import Role as UserRolefrom BookStore.app.models.model import User as UserModellogger = logging.getLogger(__name__)def init_admin(db: Session):    logger.info("Init default user...")    uname = settings.ADMIN_USERNAME    stmt = select(UserModel).where(UserModel.username == uname)    result = db.execute(stmt).scalars().unique().one_or_none()    if result:        return    packaged_user = UserModel(        roles=[db.query(UserRole).filter(UserRole.name == "Administrator").first()],        username=settings.ADMIN_USERNAME,        password=settings.ADMIN_PASSWORD,        is_active=True,    )    db.add(packaged_user)    db.commit()    db.refresh(packaged_user)